"""OData $filter emitter for the odq query DSL."""

from __future__ import annotations

import re
from typing import Any

from query_lexer import LexError
from query_parser import And, Comparison, FunctionCall, Not, Or, ParseError, parse

__all__ = ["compile_filter", "EmitError", "ParseError", "LexError"]

_OP_MAP = {
    "=": "eq",
    "!=": "ne",
    "<": "lt",
    "<=": "le",
    ">": "gt",
    ">=": "ge",
}

_SUPPORTED_FUNCTIONS = {"contains", "startswith"}
_KEYWORDS = {"and", "or", "not"}
_STRING_LITERAL_RE = re.compile(r"'(?:[^']|'')*'")
_CALL_RE = re.compile(r"([A-Za-z_][A-Za-z0-9_]*)\s*\(")


class EmitError(Exception):
    """Raised when the emitter encounters an operator or function it does not support."""


def compile_filter(text: str) -> str:
    """Compile odq query DSL text into an OData `$filter` string."""
    _reject_unsupported_calls(text)
    ast = parse(text)
    return _emit(ast)


def _reject_unsupported_calls(text: str) -> None:
    stripped = _STRING_LITERAL_RE.sub("''", text)
    for match in _CALL_RE.finditer(stripped):
        name = match.group(1)
        if name in _KEYWORDS or name in _SUPPORTED_FUNCTIONS:
            continue
        raise EmitError(f"unsupported function: {name}")


def _emit(node: Any) -> str:
    if isinstance(node, Comparison):
        return f"{node.field} {_emit_op(node.op)} {_emit_value(node.value)}"
    if isinstance(node, FunctionCall):
        if node.name not in _SUPPORTED_FUNCTIONS:
            raise EmitError(f"unsupported function: {node.name}")
        return f"{node.name}({node.field}, {_emit_value(node.value)})"
    if isinstance(node, And):
        return f"{_emit_operand(node.left)} and {_emit_operand(node.right)}"
    if isinstance(node, Or):
        return f"{_emit_operand(node.left)} or {_emit_operand(node.right)}"
    if isinstance(node, Not):
        return f"not ({_emit(node.operand)})"
    raise EmitError(f"unsupported expression: {type(node).__name__}")


def _emit_operand(node: Any) -> str:
    return f"({_emit(node)})"


def _emit_op(op: str) -> str:
    try:
        return _OP_MAP[op]
    except KeyError as exc:
        raise EmitError(f"unsupported operator: {op}") from exc


def _emit_value(value: Any) -> str:
    if isinstance(value, bool):
        return "true" if value else "false"
    if isinstance(value, str):
        return "'{}'".format(value.replace("'", "''"))
    return str(value)

